// ---------- ДАННЫЕ ----------

// Массив постов в памяти (пока без сервера)
let posts = [];
let nextPostId = 1;

// массив временных меток последних публикаций (в миллисекундах)
let postTimestamps = [];

// ---------- УТИЛИТЫ ----------

function createPostObject(text, imageUrl) {
  return {
    id: nextPostId++,
    username: "Гость",
    handle: "@guest",
    text,
    imageUrl: imageUrl || null,
    likes: 0,
    liked: false,
    createdAt: Date.now()
  };
}

// Сортировка: сначала по лайкам (убывание), затем по времени (новее выше)
function sortPosts() {
  posts.sort((a, b) => {
    if (b.likes !== a.likes) {
      return b.likes - a.likes;
    }
    return b.createdAt - a.createdAt;
  });
}

// ---------- РЕНДЕРИНГ ПОСТОВ ----------

const postsListEl = document.getElementById("posts-list");

function renderPosts() {
  postsListEl.innerHTML = "";

  sortPosts();

  posts.forEach((post) => {
    const li = document.createElement("li");
    li.className = "post";
    li.dataset.id = post.id;

    // Аватар
    const avatar = document.createElement("div");
    avatar.className = "post-avatar";

    // Контент поста
    const content = document.createElement("div");
    content.className = "post-content";

    // Верхняя часть (имя + хэндл)
    const header = document.createElement("div");
    header.className = "post-header";

    const username = document.createElement("span");
    username.className = "post-username";
    username.textContent = post.username;

    const handle = document.createElement("span");
    handle.className = "post-handle";
    handle.textContent = post.handle;

    header.appendChild(username);
    header.appendChild(handle);

    // Текст поста
    const text = document.createElement("div");
    text.className = "post-text";
    text.textContent = post.text;

    content.appendChild(header);
    content.appendChild(text);

    // Фото, если есть
    if (post.imageUrl) {
      const imageWrapper = document.createElement("div");
      imageWrapper.className = "post-image-wrapper";

      const img = document.createElement("img");
      img.className = "post-image";
      img.src = post.imageUrl;
      img.alt = "Изображение поста";

      imageWrapper.appendChild(img);
      content.appendChild(imageWrapper);
    }

    // Нижняя панель (лайки + комментарии)
    const footer = document.createElement("div");
    footer.className = "post-footer";

    // Кнопка лайка
    const likeButton = document.createElement("button");
    likeButton.className = "like-button";

    const likeIcon = document.createElement("img");
    likeIcon.className = "like-icon";
    likeIcon.src = post.liked ? "menu-icons/like1.svg" : "menu-icons/like.svg";
    likeIcon.alt = "Лайк";

    const likeCount = document.createElement("span");
    likeCount.className = "like-count";
    likeCount.textContent = post.likes;

    likeButton.appendChild(likeIcon);
    likeButton.appendChild(likeCount);

    likeButton.addEventListener("click", () => {
      toggleLike(post.id);
    });

    // Кнопка комментариев
    const commentButton = document.createElement("button");
    commentButton.className = "comment-button";
    commentButton.type = "button";

    const commentIcon = document.createElement("img");
    commentIcon.className = "comment-icon";
    commentIcon.src = "menu-icons/comments.svg";
    commentIcon.alt = "Комментарии";

    commentButton.appendChild(commentIcon);

    // Пока без обработчика клика (меню не работает)

    footer.appendChild(likeButton);
    footer.appendChild(commentButton);
    content.appendChild(footer);

    li.appendChild(avatar);
    li.appendChild(content);
    postsListEl.appendChild(li);
  });
}

// ---------- ЛАЙКИ ----------

function toggleLike(postId) {
  const post = posts.find((p) => p.id === postId);
  if (!post) return;

  post.liked = !post.liked;
  post.likes = post.liked ? post.likes + 1 : Math.max(0, post.likes - 1);

  renderPosts();
}

// ---------- РАБОТА С ФОРМОЙ СОЗДАНИЯ ПОСТА ----------

const createPostForm = document.getElementById("create-post-form");
const postTextInput = document.getElementById("post-text");
const postImageInput = document.getElementById("post-image");

// Авторасширение поля ввода поста
const charLimit = 1000;

function autoResize() {
  postTextInput.style.height = 'auto';
  postTextInput.style.height = postTextInput.scrollHeight + 'px';

  // Обновляем блок создания поста
  const createPostInner = document.querySelector('.create-post-inner');
  if (createPostInner) {
    createPostInner.style.height = 'auto';
  }
}

postTextInput.addEventListener('input', autoResize);

// Ограничение символов и управление кнопкой
function updateCharCount() {
  const currentLength = postTextInput.value.length;
  const remaining = charLimit - currentLength;
  const charCountElement = document.getElementById('char-count') || createCharCountElement();
  const submitButton = document.querySelector('.btn-primary');

  if (currentLength > charLimit) {
    // Превышен лимит
    charCountElement.textContent = `-${currentLength - charLimit}`;
    charCountElement.style.color = '#ef4444';
    submitButton.style.opacity = '0.5';
    submitButton.style.cursor = 'not-allowed';
    submitButton.disabled = true;
  } else if (currentLength >= 900) {
    // Показываем оставшиеся символы (серым цветом)
    charCountElement.textContent = `${remaining}`;
    charCountElement.style.color = '#8b98a5';
    submitButton.style.opacity = '1';
    submitButton.style.cursor = 'pointer';
    submitButton.disabled = false;
  } else {
    // В пределах лимита, но меньше 900 символов
    charCountElement.textContent = '';
    submitButton.style.opacity = '1';
    submitButton.style.cursor = 'pointer';
    submitButton.disabled = false;
  }
}

function createCharCountElement() {
  const charCount = document.createElement('div');
  charCount.id = 'char-count';
  charCount.className = 'char-count';
  charCount.textContent = '';

  const createPostFooter = document.querySelector('.create-post-footer');
  if (createPostFooter) {
    createPostFooter.before(charCount);
  }

  return charCount;
}

postTextInput.addEventListener('input', updateCharCount);
postTextInput.addEventListener('keyup', updateCharCount);
postTextInput.addEventListener('paste', (e) => {
  setTimeout(updateCharCount, 10);
});

createPostForm.addEventListener("submit", (event) => {
  event.preventDefault();

  const text = postTextInput.value.trim();
  const errorEl = document.getElementById("post-error");
  const now = Date.now();

  // Проверка лимита символов
  if (text.length > charLimit) {
    if (errorEl) {
      errorEl.style.display = "block";
      errorEl.textContent = "Слишком длинный пост, сократите до 1000 символов";
    }
    return;
  }

  // очищаем старые записи старше 60 секунд
  postTimestamps = postTimestamps.filter(ts => now - ts < 60_000);

  // если за последнюю минуту уже 2 поста — блокируем
  if (postTimestamps.length >= 2) {
    if (errorEl) {
      errorEl.style.display = "block";
      errorEl.textContent = "не спамь, погоди минуту";
    }
    return; // не публикуем пост
  }

  // если текст пустой — просто выходим (ошибку не показываем)
  if (!text) {
    return;
  }

  // лимит не превышен — можно публиковать
  if (errorEl) {
    errorEl.style.display = "none";
  }

  const file = postImageInput.files[0];

  // фиксируем время публикации
  postTimestamps.push(now);

  // Если нет картинки
  if (!file) {
    const newPost = createPostObject(text, null);
    posts.unshift(newPost);
    postTextInput.value = "";
    postImageInput.value = "";
    autoResize();
    updateCharCount();
    renderPosts();
    return;
  }

  // Если есть картинка, читаем ее как dataURL
  const reader = new FileReader();
  reader.onload = function (e) {
    const imageUrl = e.target.result;
    const newPost = createPostObject(text, imageUrl);
    posts.unshift(newPost);
    postTextInput.value = "";
    postImageInput.value = "";
    autoResize();
    updateCharCount();
    renderPosts();
  };
  reader.readAsDataURL(file);
});

// ---------- НАВИГАЦИЯ МЕЖДУ СТРАНИЦАМИ ----------

const navButtons = document.querySelectorAll(".nav-item");
const pages = document.querySelectorAll(".page");

// Карта всех иконок
const iconMap = {
  home: {
    default: "menu-icons/feed.svg",
    hover:   "menu-icons/feed1.svg",
    active:  "menu-icons/feed2.svg"
  },
  search: {
    default: "menu-icons/explore.svg",
    hover:   "menu-icons/explore1.svg",
    active:  "menu-icons/explore2.svg"
  },
  notifications: {
    default: "menu-icons/notifications.svg",
    hover:   "menu-icons/notifications1.svg",
    active:  "menu-icons/notifications2.svg"
  },
  account: {
    default: "menu-icons/user.svg",
    hover:   "menu-icons/user1.svg",
    active:  "menu-icons/user2.svg"
  }
};

navButtons.forEach((btn) => {
  const pageKey = btn.dataset.page;
  const img = btn.querySelector(".nav-icon");

  // Стартовая иконка — обычная для неактивных, активная для активных
  if (iconMap[pageKey] && img) {
    if (btn.classList.contains("nav-item-active")) {
      img.src = iconMap[pageKey].active;
    } else {
      img.src = iconMap[pageKey].default;
    }
  }

  // HOVER: только для неактивных кнопок и только на десктопе
  btn.addEventListener("mouseenter", () => {
    const key = btn.dataset.page;
    const imgEl = btn.querySelector(".nav-icon");

    // Проверяем, что это не мобильное устройство (ширина экрана > 640px)
    if (window.innerWidth > 640 && !btn.classList.contains("nav-item-active") && iconMap[key] && imgEl) {
      imgEl.src = iconMap[key].hover;   // *1.svg
    }
  });

  btn.addEventListener("mouseleave", () => {
    const key = btn.dataset.page;
    const imgEl = btn.querySelector(".nav-icon");

    // Проверяем, что это не мобильное устройство (ширина экрана > 640px)
    if (window.innerWidth > 640 && !btn.classList.contains("nav-item-active") && iconMap[key] && imgEl) {
      imgEl.src = iconMap[key].default; // обратно *.svg
    }
  });

  // КЛИК: меняем активную кнопку и показываем страницу
  btn.addEventListener("click", () => {
    const target = btn.dataset.page;

    // 1) Снять активность со всех и вернуть обычные иконки
    navButtons.forEach((b) => {
      b.classList.remove("nav-item-active");

      const key = b.dataset.page;
      const imgEl = b.querySelector(".nav-icon");

      if (iconMap[key] && imgEl) {
        imgEl.src = iconMap[key].default;
      }
    });

    // 2) Текущая кнопка становится активной — ставим *2.svg
    btn.classList.add("nav-item-active");
    if (iconMap[target] && img) {
      img.src = iconMap[target].active;
    }

    // 3) Переключаем страницы
    pages.forEach((page) => {
      page.hidden = !page.classList.contains(`page-${target}`);
    });
  });
});

// ---------- НАЧАЛЬНЫЕ ДАННЫЕ (опционально) ----------

// Пара тестовых постов, чтобы лента не была пустой при первой загрузке
posts = [
  createPostObject("Добро пожаловать в «тупо». Это первый тестовый пост без картинки."),
  createPostObject("А это пост с тестовой картинкой. Можно загрузить свою, когда будете писать пост.")
];

// Для примера добавим лайков, чтобы увидеть сортировку
posts[0].likes = 3;
posts[0].liked = false;
posts[1].likes = 5;
posts[1].liked = false;

// Рендерим ленту при загрузке
renderPosts();

// Инициализация при загрузке
autoResize();
updateCharCount();

// Мобильная версия - обработка всплывающего окна создания поста
const mobileCreatePostBtn = document.getElementById('mobile-create-post-btn');
const mobileCreatePostModal = document.getElementById('mobile-create-post-modal');
const mobileCloseBtn = document.getElementById('mobile-close-btn');
const mobileCreatePostForm = document.getElementById('mobile-create-post-form');
const mobilePostText = document.getElementById('mobile-post-text');
const mobileCharCount = document.getElementById('mobile-char-count');
const mobilePostImage = document.getElementById('post-image'); // Используем тот же input для загрузки фото

if (mobileCreatePostBtn && mobileCreatePostModal) {
  // Открытие модального окна
  mobileCreatePostBtn.addEventListener('click', () => {
    mobileCreatePostModal.classList.add('active');
    mobilePostText.focus();
  });

  // Закрытие модального окна
  mobileCloseBtn.addEventListener('click', () => {
    mobileCreatePostModal.classList.remove('active');
    mobilePostText.value = '';
    mobileCharCount.textContent = '';
  });

  // Закрытие при клике вне окна
  mobileCreatePostModal.addEventListener('click', (e) => {
    if (e.target === mobileCreatePostModal) {
      mobileCreatePostModal.classList.remove('active');
      mobilePostText.value = '';
      mobileCharCount.textContent = '';
    }
  });

  // Авторасширение поля ввода в мобильной версии
  function mobileAutoResize() {
    mobilePostText.style.height = 'auto';
    mobilePostText.style.height = mobilePostText.scrollHeight + 'px';
  }

  mobilePostText.addEventListener('input', mobileAutoResize);

  // Ограничение символов для мобильной версии
  function mobileUpdateCharCount() {
    const currentLength = mobilePostText.value.length;
    const remaining = charLimit - currentLength;

    if (currentLength > charLimit) {
      mobileCharCount.textContent = `-${currentLength - charLimit}`;
      mobileCharCount.style.color = '#ef4444';
    } else if (currentLength >= 900) {
      mobileCharCount.textContent = `${remaining}`;
      mobileCharCount.style.color = '#8b98a5';
    } else {
      mobileCharCount.textContent = '';
    }
  }

  mobilePostText.addEventListener('input', mobileUpdateCharCount);
  mobilePostText.addEventListener('keyup', mobileUpdateCharCount);
  mobilePostText.addEventListener('paste', (e) => {
    setTimeout(mobileUpdateCharCount, 10);
  });

  // Обработка загрузки фото в мобильной версии
  const mobilePostImageInput = document.getElementById('mobile-post-image');
  let mobileImagePreview = null;

  if (mobilePostImageInput) {
    // Создаем контейнер для превью
    const previewContainer = document.createElement('div');
    previewContainer.className = 'image-preview-container';
    previewContainer.style.marginBottom = '16px';
    previewContainer.style.position = 'relative';

    const previewImage = document.createElement('img');
    previewImage.className = 'image-preview';
    previewImage.style.maxWidth = '100%';
    previewImage.style.maxHeight = '150px';
    previewImage.style.borderRadius = '16px';
    previewImage.style.display = 'none';
    previewImage.style.marginBottom = '12px';

    const removePreviewBtn = document.createElement('button');
    removePreviewBtn.className = 'remove-preview-btn';
    removePreviewBtn.textContent = '×';
    removePreviewBtn.style.position = 'absolute';
    removePreviewBtn.style.top = '8px';
    removePreviewBtn.style.right = '8px';
    removePreviewBtn.style.width = '24px';
    removePreviewBtn.style.height = '24px';
    removePreviewBtn.style.borderRadius = '50%';
    removePreviewBtn.style.backgroundColor = 'rgba(0, 0, 0, 0.6)';
    removePreviewBtn.style.color = 'white';
    removePreviewBtn.style.border = 'none';
    removePreviewBtn.style.cursor = 'pointer';
    removePreviewBtn.style.fontSize = '14px';
    removePreviewBtn.style.display = 'none'; // Скрываем кнопку изначально

    previewContainer.appendChild(previewImage);
    previewContainer.appendChild(removePreviewBtn);

    // Вставляем контейнер превью перед полем ввода
    const mobilePostInputContainer = document.querySelector('.mobile-post-input-container');
    if (mobilePostInputContainer) {
      mobilePostInputContainer.before(previewContainer);
    }

    mobileImagePreview = previewImage;

    // Обработка выбора файла
    mobilePostImageInput.addEventListener('change', function(e) {
      const file = e.target.files[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = function(event) {
          mobileImagePreview.src = event.target.result;
          mobileImagePreview.style.display = 'block';
          removePreviewBtn.style.display = 'block'; // Показываем кнопку крестика
        };
        reader.readAsDataURL(file);
      }
    });

    // Обработка удаления превью
    removePreviewBtn.addEventListener('click', function(e) {
      e.preventDefault();
      mobileImagePreview.style.display = 'none';
      mobileImagePreview.src = '';
      mobilePostImageInput.value = '';
    });
  }

  // Обработка отправки формы в мобильной версии
  mobileCreatePostForm.addEventListener('submit', (e) => {
    e.preventDefault();

    const text = mobilePostText.value.trim();
    if (text.length > charLimit) {
      alert('Слишком длинный пост, сократите до 1000 символов');
      return;
    }

    if (!text) {
      return;
    }

    // Проверяем, есть ли загруженное фото
    const file = mobilePostImageInput.files[0];
    let imageUrl = null;

    if (file) {
      const reader = new FileReader();
      reader.onload = function(event) {
        imageUrl = event.target.result;
        const newPost = createPostObject(text, imageUrl);
        posts.unshift(newPost);
        renderPosts();

        // Закрываем модальное окно и очищаем форму
        mobileCreatePostModal.classList.remove('active');
        mobilePostText.value = '';
        mobileCharCount.textContent = '';
        if (mobileImagePreview) {
          mobileImagePreview.style.display = 'none';
          mobileImagePreview.src = '';
        }
        mobilePostImageInput.value = '';
      };
      reader.readAsDataURL(file);
    } else {
      // Без фото
      const newPost = createPostObject(text, null);
      posts.unshift(newPost);
      renderPosts();

      // Закрываем модальное окно и очищаем форму
      mobileCreatePostModal.classList.remove('active');
      mobilePostText.value = '';
      mobileCharCount.textContent = '';
      if (mobileImagePreview) {
        mobileImagePreview.style.display = 'none';
        mobileImagePreview.src = '';
      }
      mobilePostImageInput.value = '';
    }
  });
}

// Обработчик изменения размера окна для обновления иконок при смене режима (десктоп/мобильный)
window.addEventListener("resize", () => {
  navButtons.forEach((btn) => {
    const key = btn.dataset.page;
    const imgEl = btn.querySelector(".nav-icon");

    if (iconMap[key] && imgEl) {
      if (btn.classList.contains("nav-item-active")) {
        // Для активных кнопок всегда ставим активную иконку
        imgEl.src = iconMap[key].active;
      } else {
        // Для неактивных ставим обычную иконку
        imgEl.src = iconMap[key].default;
      }
    }
  });
});
